async (params, browser) => {
  // Open paper page
  await browser.open(`https://arxiv.org/abs/${params.paper_id}`)

  // Wait for page
  await browser.waitForSelector('h1.title, .title.mathjax', 15000)

  // Let page render
  await browser.wait(2000)

  // Extract paper info
  const paper_data = await browser.evaluate(`const title = document.querySelector('h1.title')?.textContent?.replace('Title:', '')?.trim() || ''; const authors = []; document.querySelectorAll('.authors a').forEach(a => authors.push(a.textContent?.trim())); const abstract = document.querySelector('blockquote.abstract')?.textContent?.replace('Abstract:', '')?.trim() || ''; const cats = document.querySelector('.tablecell.subjects')?.textContent?.trim() || ''; const dateEl = document.querySelector('.dateline')?.textContent?.trim() || ''; const pdfLink = 'https://arxiv.org/pdf/' + params.paper_id + ''; return { paper_id: '' + params.paper_id + '', title, authors, abstract, categories: cats, date: dateEl, pdf_link: pdfLink, url: window.location.href };`)

  return paper_data
}
